"""
MKT Context Commentary — Genesis chapters 13–16
Run: python3 scripts/zc-context-genesis-13-16.py

Source data used:
- data/interlinear/genesis.json
- data/translation/draft/mediating/genesis.json (MKT text)
- data/commentary/mkt-context/genesis.json (ch15:v17 already present; merge_comm skips it)

Key decisions in this range:
- Ch14:v1 Amraphel/Hammurabi: identification noted as debated; not asserted
- Ch14:v13 "Abram the Hebrew": first use of ʿiḇrî noted
- Ch14:v18 Melchizedek: Salem=Jerusalem via Ps 76:2; ʾEl ʿElyôn=YHWH per Abram's v22 equation
- Ch15:v2 Eliezer heir: Nuzi tablet adoption-of-slave ANE practice identified
- Ch15:v6: Paul's justification-by-faith citation (Rom 4:3; Gal 3:6) noted; ḥāšaḇ
  accounting vocabulary explained without overloading the context layer
- Ch15:v12 tardemāh: same word as Adam's deep sleep (2:21); noted as theophanic trance
- Ch15:v16 sin of Amorites not yet full: divine patience with Canaanites before judgment
- Ch16:v2 ʾibbāneh wordplay (build/son): Hammurabi Code 144-145 legal background
- Ch16:v12 Ishmael wild-donkey: characterized as freedom/nomadic, not cursed
- Ch16:v13 Hagar names God ʾEl Roʾî: only human to name God in the OT; mutual seeing noted
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

GENESIS_CONTEXT = {
  "13": {
    "1": """<p>The verb "went up" (<em>wayyaʿal</em>) is the directional standard for travel from Egypt toward Canaan — topographically accurate (the Sinai peninsula rises into the hill country of Canaan) and covenantally resonant (return to the land of promise). The mention of Lot's continued presence with Abram reinstates the covenant household unit that the Egypt episode of ch12 had left intact: "his wife and everything he had, and Lot went with him." The Negev functions as the transitional zone between Egypt and Canaan in the patriarchal itineraries — Abram re-enters his covenant territory by the same route he left it.</p>""",
    "2": """<p>"Abram had become very wealthy in livestock and in silver and gold" — the three-category wealth inventory (livestock, silver/monetary metal, gold/precious metal) represents the primary forms of ANE pastoral wealth. Livestock was productive capital (herds grew and generated income); silver was the standard monetary medium in Mesopotamia and Canaan (coined money had not yet been invented — silver was weighed by the shekel); gold was the prestige metal of the wealthy. This wealth notation fulfills the Egypt episode's dark irony: Abram's deception (12:11-13) was followed by divine protection and material gain. The narrator notes the wealth without moralizing its source.</p>""",
    "3": """<p>"From the Negev he went from place to place until he came to Bethel" — the phrase "from place to place" (<em>lĕmasSāʿāyw</em>, literally "by his stages/encampments") describes the semi-nomadic pattern of moving between established camping stations. Abram is retracing his original northward journey from 12:9 in reverse. The journey to Bethel is a covenant-recommitment movement: returning to the altar he built on his first entry into Canaan (12:8) before the Egypt detour interrupted the covenant journey. The geographic return corresponds to a spiritual return.</p>""",
    "4": """<p>"Where he had first built an altar. There Abram called on the name of the LORD" — the resumption of covenant worship at the exact site of the prior altar establishes covenant continuity after the Egypt episode. The phrase "called on the name of the LORD" (<em>wayyiqrāʾ bĕšēm YHWH</em>) is the standard covenantal worship formula established in Gen 4:26 (Seth's line) and enacted by Abram at each altar site (12:8; 13:4; 21:33; 26:25). Returning to the Bethel altar rather than building a new one signals that the prior covenant-worship stands — Abram is not starting over but resuming.</p>""",
    "5": """<p>"Lot, who was moving about with Abram, also had flocks and herds and tents" — Lot's wealth is presented as a consequence of his association with Abram's covenant-household. The blessing that flows to "all peoples" through Abram (12:3) begins with his nearest traveling companion. Lot's prosperity through covenant-proximity is not elaborated theologically but embedded narratively: the one who stays near the covenant-bearer shares in the overflow. The listing of "flocks and herds and tents" mirrors Abram's own wealth-description in v2, signaling that the two households have become comparably sized.</p>""",
    "6": """<p>"The land could not support them while they stayed together, for their possessions were so great that they were not able to stay together" — pastoral economics in the ANE required large land areas per household. Ancient Near Eastern pastoral law codes (reflected in documents from Mari and Nuzi) dealt extensively with grazing rights, water access, and inter-household pastoral conflicts. The Canaanite landscape — hilly, with limited valleys suitable for extensive grazing — had a finite carrying capacity. The conflict is not moral failure but material reality: too many animals for too little land. The land itself imposes the separation.</p>""",
    "7": """<p>"Quarreling arose between Abram's herders and Lot's herders. The Canaanites and Perizzites were also living in the land at that time" — the mention of existing inhabitants adds contextual pressure: the available pastureland was not exclusively available to Abram and Lot. The Perizzites (<em>Pĕrizzî</em>) — "those of the open country" or "village-dwellers" (from <em>pĕrāzāh</em>, an unwalled town) — are listed among the pre-Israelite inhabitants of Canaan throughout the OT (Deut 7:1; Josh 3:10; Judg 1:4-5; Ezra 9:1; Neh 9:8). Their presence signals that the pastureland conflict occurs within a contested landscape where the covenant-household must negotiate space with existing residents.</p>""",
    "8": """<p>"For we are close relatives (<em>ʾănāšîm ʾăḥîm</em>)" — literally "we are men who are brothers." The appeal to kinship solidarity is the ANE basis for peaceful resolution of internal disputes. Family honor in the ancient world required that disputes within the kinship group be resolved without bloodshed — inter-family violence was a matter of clan-shame. Abram's appeal ("let's not have quarreling between you and me") is both a social norm invocation and a personal request: the covenant-patriarch is protecting the household's internal cohesion. His generosity in v9 — offering Lot first choice — goes beyond the requirement of the social norm.</p>""",
    "9": """<p>"Is not the whole land before you? Let's part company" — Abram's offer of first choice to Lot is remarkable from an ANE honor perspective. As the elder kinsman, the covenant-bearer, and the one who initiated the journey, Abram had both the social right and the expectation of choosing first. His deferral to Lot inverts the hierarchical priority that ANE culture would have expected. The covenant context explains the inversion: Abram can afford to be generous because YHWH has already promised him "all the land" (vv14-17). Covenant-security generates covenant-generosity — trust in divine provision liberates from the competition for advantage.</p>""",
    "10": """<p>"Lot looked around and saw that the whole plain of the Jordan toward Zoar was well watered, like the garden of the LORD, like the land of Egypt" — the two comparisons frame the Jordan valley's appeal through Lot's knowledge: the "garden of the LORD" (Eden-like, from 2:8-10's river-watered garden) and Egypt (the Nile-irrigated land Lot had just experienced, 12:10-20). The Jordan valley in the Bronze Age was indeed heavily forested and irrigated — the Dead Sea region was not always the barren salt-flat it became after Sodom's destruction. The narrator's parenthetical ("before the LORD destroyed Sodom and Gomorrah") is a pointed foreshadowing: the choice that looks best will lead to catastrophe.</p>""",
    "11": """<p>"Lot chose for himself the whole plain of the Jordan and set out toward the east" — the eastward movement carries the narrative's consistent theological direction: Adam and Eve were expelled east of Eden (3:24); Cain went east of Eden to Nod (4:16); the Babel builders moved eastward (11:2). Now Lot moves eastward toward the Jordan plain, away from Canaan (the covenant land, to the west). The directional choice maps the covenant trajectories: Abram stays in Canaan (covenant land), Lot moves east (away from the covenant center). "The two men parted company" — the separation is clean and mutual, without bitterness, but permanent in its covenant significance.</p>""",
    "12": """<p>"Abram lived in the land of Canaan, while Lot lived among the cities of the plain and pitched his tents near Sodom" — the geographic contrast encodes the theological contrast. The land of Canaan is the covenant-territory; the cities of the plain are identified with Sodom, already under divine condemnation (v13). Lot's progressive entanglement with Sodom — from "near Sodom" here (13:12) to "sitting in the gateway of Sodom" (19:1, a position of civic leadership and commerce) — charts a gradual cultural assimilation into the condemned city. The tents near Sodom mark only the beginning of a trajectory that ends in the rescue of ch19.</p>""",
    "13": """<p>"The people of Sodom were wicked (<em>rāʿîm</em>) and were sinning greatly (<em>ḥaṭṭāʾîm mĕʾōḏ</em>) against the LORD" — the narrator's judicial verdict follows immediately after Lot's choice to settle near Sodom, creating a stark dramatic irony: Lot chose the best land without knowing its moral condition before YHWH. The double intensification (wicked + sinning greatly) functions as an anticipatory verdict — the reader knows what Lot does not, and the narrator is preparing for the destruction of ch19. "Against the LORD" (<em>laYHWH</em>) specifies that the Sodomites' wickedness is not merely social disruption but covenant-violation against the divine sovereign of all nations.</p>""",
    "14": """<p>"The LORD said to Abram after Lot had parted from him" — the covenant reaffirmation comes precisely after the separation: Lot's departure does not diminish the promise; YHWH reaffirms and expands it. The timing is significant: the direction given to Abram — "look north and south, east and west" — is the four-direction survey formula for possessing territory. In ANE legal practice, the symbolic survey of territory from an elevated viewpoint was a form of territorial claim-staking. The same gesture will be enacted on Mount Nebo (Deut 34:1-4) before the conquest — and what Abram sees promised, Moses will see about to be fulfilled.</p>""",
    "15": """<p>"All the land that you see I will give to you and your offspring (<em>lĕzarʿăkā</em>) forever (<em>ʿad-ʿôlām</em>)" — the promise includes the temporal qualifier "forever" (<em>ʿad-ʿôlām</em>) — the same <em>ʿôlām</em> (everlasting) language of the Noahic covenant (9:16). The land promise is not provisional but permanent. The word "offspring" (<em>zeraʿ</em>) is deliberately singular in Hebrew — a collective noun that can mean one descendant or many. Paul will argue from this grammatical singularity (Gal 3:16) that the promise is ultimately to "the seed" (Christ) through whom all descendants receive the inheritance. The Abrahamic land promise is not merely about real estate but about the eschatological inheritance.</p>""",
    "16": """<p>"I will make your offspring like the dust of the earth" — the dust-comparison for the promised offspring is the third major image for the patriarchal multitude (stars in 15:5; sand in 22:17; dust here). Together these three comparisons (from above, below, and the boundary — stars/sky, dust/earth, sand/sea) represent total-encompassing uncountability. The dust image specifically echoes 2:7 (Adam formed from dust) and 3:19 (you will return to dust) — the human substance that seemed condemned to death (returning to dust) becomes the material of a promised multitude. What the Fall made into a death-image, the covenant promise makes into a hope-image.</p>""",
    "17": """<p>"Go, walk through the length and breadth of the land, for I am giving it to you" — the walk-through command is a legal land-claim ritual. In ANE practice (attested in Hittite land grants and Mesopotamian property law), physical traversal of a territory was a recognized form of taking possession — the boundary-walk made the claim concrete. The same principle underlies the inheritance walk of Josh 18:4,8 (Joshua sends men to survey the land before allotting it to the remaining tribes). Abram's commanded walk through Canaan is a symbolic land-taking performed under divine commission — the covenant-deed preceded by covenant-survey.</p>""",
    "18": """<p>"The great trees of Mamre at Hebron, where he pitched his tents" — Hebron (approximately 30 km south of Jerusalem) becomes the primary patriarchal center of Genesis: Abraham, Sarah, Isaac, Rebekah, Jacob, and Leah are all buried at the cave of Machpelah near Hebron (23:19; 25:9-10; 49:29-32; 50:13). The "great trees of Mamre" (<em>ʾēlônê Mamrê</em>) mark a sacred grove — the site of the theophany of ch18 where YHWH appears with two angels. Abram's altar here is his fourth in Canaan (Shechem, 12:7; Bethel, 12:8; Bethel again, 13:4; Hebron, 13:18) — a network of covenant worship sites that geographically stakes the covenant claim on the promised land through sanctified ground.</p>"""
  },
  "14": {
    "1": """<p>The four eastern kings — Amraphel of Shinar (the identification with Hammurabi of Babylon is historically debated and cannot be confirmed), Arioch of Ellasar (location uncertain — possibly Larsa in Babylonia), Kedorlaomer of Elam (the Elamite kingdom east of Mesopotamia was a real major ANE power; Elamite kings periodically exercised control over Mesopotamian city-states), and Tidal of Goyim (literally "king of nations/peoples" — possibly a mixed-nation coalition leader) — represent a coalition of eastern imperial powers projecting force into the Syro-Canaanite corridor. The geography of the campaign (from Babylonia and Elam westward into Transjordan and the Jordan valley) reflects the real reach of Mesopotamian imperial power in the Middle Bronze Age.</p>""",
    "2": """<p>The five city-state kings of the "cities of the plain" — Sodom, Gomorrah, Admah, Zeboyim, Bela/Zoar — represent the local Canaanite political units of the southern Jordan valley. The five-city confederation (ḥamēš malkîm against the four eastern kings — "five against four") is a standard ANE political arrangement for small city-states facing a common threat. These five cities have already been identified in 10:19 as within the borders of Canaan — their political subjugation to an Elamite coalition is the ANE background against which Abram's rescue operation will be evaluated.</p>""",
    "3": """<p>"All these latter kings joined forces in the Valley of Siddim (that is, the Dead Sea Valley)" — the Valley of Siddim is identified with the Dead Sea (yam hammelaḥ, Salt Sea) region. An ancient tradition holds that the cities of the plain were located at the southern end of the Dead Sea or in the now-submerged southern basin — supported by some geological and archaeological evidence showing large Bronze Age settlements on the plain's margins. The current Dead Sea landscape (hypersaline, lifeless, below sea level) contrasts starkly with the "well-watered" description of 13:10, consistent with the catastrophic transformation described in ch19.</p>""",
    "4": """<p>"For twelve years they had been subject to Kedorlaomer, but in the thirteenth year they rebelled" — the twelve-year submission / thirteenth-year rebellion pattern is the standard ANE suzerain-vassal relationship cycle: the vassal city-states pay annual tribute (ʿeḇôdāh) to the great king and eventually rebel when the imperial power weakens or the tribute burden becomes intolerable. The Amarna Letters (14th century BCE Egyptian diplomatic correspondence) document numerous instances of Canaanite city-states oscillating between submission and rebellion against their imperial overlords. The political context of ch14 is authentic to the ANE power dynamics of the period.</p>""",
    "5": """<p>Kedorlaomer's punitive campaign sweeps through the Transjordan, defeating multiple pre-Israelite peoples: the Rephaites (<em>Rĕpāʾîm</em>) of Ashteroth-Karnaim (giant peoples associated with Bashan — later connected to Og of Bashan, Deut 3:11; Josh 12:4), the Zuzites of Ham (possibly the Zamzummim of Deut 2:20), the Emites of Shaveh-Kiriathaim (giant peoples of Moab, Deut 2:10-11). The campaign's geographic arc through the Transjordan encounters peoples who will later be displaced by Israel — the pre-conquest catalog maps future Israelite territory through its pre-Israelite occupants.</p>""",
    "6": """<p>The Horites (<em>Ḥōrî</em>, possibly the Hurrians or cave-dwellers) in the hill country of Seir — the Edomite territory south of the Dead Sea. Deut 2:12,22 records that the Edomites (descendants of Esau) dispossessed the Horites from Seir. The campaign reaches as far south as El Paran "near the desert" — the northern Sinai boundary. The scope of the eastern coalition's campaign is extraordinary: from the Transjordan north (Ashteroth-Karnaim) to the southern desert (El Paran) — a sweep of the entire eastern and southern boundary of Canaan before attacking the Jordan valley cities.</p>""",
    "7": """<p>En Mishpat (= Kadesh, the spring of judgment — the same Kadesh where Israel will later camp during the wilderness wandering, Num 13:26; 20:1) and Hazezon Tamar (= En Gedi on the western Dead Sea shore, 2 Chr 20:2). The Amalekites (<em>ʿAmālēq</em>) — a nomadic people of the Negev and Sinai who will be Israel's persistent enemy (Exod 17:8-16; 1 Sam 15); and the Amorites of Hazezon Tamar. The geographic catalog of ch14's campaign is remarkably specific — named places that appear throughout the subsequent Israelite narrative, lending the chapter the character of an authentic historical record from a tradition independent of the main Genesis source.</p>""",
    "8": """<p>The five Canaanite city-state kings march out from their cities to the Valley of Siddim to give battle — a defensive mobilization against the returning punitive expedition. The "drawing up of battle lines" (<em>wayyaʿarĕḵû ʾittām milḥāmāh</em>) is the standard military engagement formula. The valley location for the battle reflects ANE military preference for open terrain where chariot warfare and massed infantry could be deployed. The five kings defending their territory against the four kings represents the local Canaanite confederation resisting Mesopotamian imperial enforcement of tribute — a political conflict into which Abram will be drawn through his kinship obligation to Lot.</p>""",
    "9": """<p>The formal statement "four kings against five" (<em>ʾarbaʿāh mĕlāḵîm ʾet-haḥāmiššāh</em>) summarizes the battle in terms of the coalition sizes before describing the outcome. The literary technique of stating the numbers before the action is a characteristic biblical battle-narrative device (cf. Judg 7:3-8 Gideon's reduction from 32,000 to 300; 1 Sam 13:5 the Philistine force enumeration). The four eastern kings (presumably better-armed and better-organized as an imperial force) will defeat the five local kings despite the numerical disadvantage — the imperial military superiority overcoming local resistance.</p>""",
    "10": """<p>"The Valley of Siddim was full of tar pits (<em>bôrôt bôrôt ḥēmār</em>)" — bitumen/asphalt pits in the Dead Sea region are well attested: Josephus describes the asphalt that floated on the Dead Sea in his time (Jewish War IV.8.4); bitumen from the Dead Sea was used in ANE construction (cf. 11:3). The tar pits contributed to the defeat of Sodom and Gomorrah's kings: fleeing forces fell into the pits. The Hebrew "some of the men fell into them" (<em>wayyippĕlû-šāmmāh</em>, they fell there) while "the rest fled to the hills" — the military rout is not total annihilation but a chaotic dispersal, with the city-state armies broken and the kings' coalition defeated.</p>""",
    "11": """<p>"The four kings seized all the goods (<em>kol-rĕḵuš</em>) of Sodom and Gomorrah and all their food" — the plunder of a defeated city-state was the standard ANE reward for military victory. The victor's appropriation of "goods and food" (the two primary wealth categories) represents both the economic penalty of defeat and the material incentive for the campaign. The eastern coalition's goal was tribute enforcement; when the vassal cities rebelled, the imperial response was direct extraction — taking what the tribute should have provided. The goods of Sodom that Abram will later refuse (vv22-23) are precisely the goods taken in this plunder.</p>""",
    "12": """<p>"They also carried off Abram's nephew Lot and his possessions, since he was living in Sodom" — the narrative focus narrows from the general military campaign to the specific event that triggers Abram's action. Lot's capture is the consequence of his earlier choice (13:12) to settle near and then in Sodom. He is carried off not because he is a target but because he is caught in the general plunder of Sodom. The phrase "since he was living in Sodom" (<em>wĕhûʾ yōšēḇ biSĕdōm</em>) is a pointed narrative note: Lot's location determined his fate — proximity to judgment brings judgment's collateral consequences.</p>""",
    "13": """<p>"A man who had escaped (<em>happāliṭ</em>) came and reported this to Abram the Hebrew (<em>haʿiḇrî</em>)" — the first use of the word "Hebrew" (<em>ʿiḇrî</em>) in the Bible, designating Abram's ethnic-covenant identity. The term <em>ʿiḇrî</em> derives from <em>ʿēḇer</em> (the ancestor of the Hebrews, 10:21) and will become the standard designation for Israel in Egypt (Gen 39:14; 40:15; 41:12; Exod 1:15-19; 2:6-11). Abram's Amorite allies (Mamre, Eshkol, Aner) are introduced as "brothers" (<em>baʿălê bĕrît ʾaḇrām</em>, covenant partners of Abram) — literally "lords of Abram's covenant" — indicating a formal alliance relationship that crosses ethnic lines and demonstrates the covenant-community's extension beyond the blood-family.</p>""",
    "14": """<p>"318 trained men born in his household (<em>yĕlîḏê bêtô</em>)" — the household-born warriors are servants trained from birth in Abram's household, distinct from hired soldiers or mercenaries. The number 318 is specific enough to suggest authentic historical tradition rather than a round number. A patriarch who could field 318 trained fighters commanded a substantial household-community — equivalent to a small chieftain's military force. Dan (the northern limit of the pursuit) is called by the name of the later Israelite tribe (Josh 19:47; Judg 18:29 — the Danites renamed the city Laish as Dan) — a geographic landmark that would have been recognizable to the text's later audience.</p>""",
    "15": """<p>Abram's night raid — dividing his forces and attacking at night — is a sound ANE tactical decision. Night attacks maximized surprise and compensated for numerical disadvantage (318 trained fighters against a returning army of four kingdoms). The same night-attack tactic is used by Gideon (Judg 7:9-22) and Jonathan (1 Sam 14:31). The pursuit as far as Hobah "north of Damascus" — Damascus being the major city of southern Syria — indicates the eastern coalition had retreated far northward before Abram's forces caught them. The rescue operation covers the full geographic scope of the original campaign reversed.</p>""",
    "16": """<p>"He recovered all the goods and brought back his relative Lot and his possessions, together with the women and the other people" — Abram's rescue is comprehensive: goods, Lot, women, other people. The scope of the rescue goes beyond the kinship obligation that motivated it — Abram recovers all the captives of Sodom, not just his nephew. This complete recovery positions Abram as a liberator for the entire region, not merely a family-member pursuing a kinsman-rescue (<em>gōʾēl</em>) obligation. The recovered women and other people of Sodom are the group whose fate will create the diplomatic tension with the king of Sodom in vv21-24.</p>""",
    "17": """<p>The Valley of Shaveh — "the King's Valley" (<em>ʿēmeq haššāwēh hûʾ ʿēmeq hammelek</em>) — is identified in 2 Sam 18:18 with a valley near Jerusalem where Absalom erected a memorial pillar. The Kidron valley (east of Jerusalem) is the traditional identification. The king of Sodom's coming out to meet Abram is a formal royal welcome for a returning military victor — the protocol for greeting a successful warrior. The meeting sets up the diplomatic encounter of vv21-24, where the king of Sodom will offer Abram the standard victor's reward and Abram will refuse it on covenant grounds.</p>""",
    "18": """<p>Melchizedek ("my king is righteousness" or "righteous king" — <em>malkî-ṣedeq</em>) appears without genealogy, without predecessor, without successor — a priest-king outside any established priestly line. Salem (<em>šālēm</em>, peace/wholeness) is identified with Jerusalem in Ps 76:2 ("His tent is in Salem, his dwelling place in Zion") — a connection that makes Melchizedek the first Jerusalemite priest-king in the biblical narrative. "Bread and wine" are covenant-hospitality elements — the meal as covenant ratification. <em>ʾEl ʿElyôn</em> (God Most High) is Abram's YHWH identified by Melchizedek's title: Abram's equation in v22 (where he swears by "YHWH, God Most High, Creator of heaven and earth") confirms these as the same deity. Melchizedek worships Abram's God.</p>""",
    "19": """<p>Melchizedek's blessing of Abram — "blessed be Abram by God Most High, Creator (<em>qōnēh</em>) of heaven and earth" — uses the divine title <em>qōnēh šāmayim wāʾāreṣ</em> (Creator/Possessor of heaven and earth), a comprehensive sovereignty formula for the supreme deity. The Heb 7:7 comment — "the lesser is blessed by the greater" — applies here: Melchizedek blesses Abram as the superior party, establishing the Melchizedek-priesthood's precedence over the Abrahamic line. The blessing flows downward from priest-king to patriarch — a hierarchy that the later Levitical priesthood (descended from Abraham) cannot supersede.</p>""",
    "20": """<p>"And praise be to God Most High, who delivered your enemies into your hand" — Melchizedek attributes the military victory to divine action; Abram is instrument, not cause. The tithe (<em>maʿăśēr</em>, a tenth) that Abram gives Melchizedek is the first tithe in the Bible — given to a non-Israelite, non-Levitical priest, outside any Mosaic law. The tithe as a recognition of divine ownership (one-tenth returned to the deity's representative acknowledges the remaining nine-tenths as held in stewardship) is a universal ANE practice. Abram's tithe to Melchizedek precedes the Levitical tithe law (Num 18:21-24) by centuries, establishing the tithe principle in the Abrahamic covenant itself — which is why Heb 7:9-10 can argue that Levi paid tithes to Melchizedek "in the loins of Abraham."</p>""",
    "21": """<p>The king of Sodom's offer — "give me the people and keep the goods for yourself" — reflects the standard ANE victor's-reward arrangement. After a liberation/rescue, the people (as subjects of the original king) belonged to their king; the goods were the victor's spoils. The king of Sodom is offering the maximum possible reward under ANE convention. In contrast to Melchizedek's theological framing of the victory (divine deliverance), the king of Sodom offers a purely transactional resolution — Abram's rescue reduced to a military-commercial exchange. Abram's refusal of this transactional frame will be the passage's theological climax.</p>""",
    "22": """<p>"With raised hand (<em>hărîmōtî yādî</em>) I have sworn an oath to the LORD, God Most High, Creator of heaven and earth" — the raised-hand gesture is the standard ANE oath posture, attested in Egyptian, Mesopotamian, and Hittite contexts (cf. Exod 6:8: YHWH "raised his hand" to swear the land oath to Israel; Deut 32:40). By explicitly equating YHWH with <em>ʾEl ʿElyôn</em> (Melchizedek's name for God), Abram confirms that the two men were worshipping the same deity under different names — the encounter was a genuine cross-cultural meeting of covenant-community members. The oath formula transforms a commercial negotiation into a covenant-loyalty statement.</p>""",
    "23": """<p>"Not even a thread or the strap of a sandal" — the hyperbolic minimal-value formula (a thread and a sandal-strap are among the cheapest items in the ANE material culture) makes Abram's refusal absolute and emphatic. The refusal's stated rationale — "so that you will never be able to say, 'I made Abram rich'" — is the theological core: Abram's wealth comes from YHWH (already established in 12:2; 13:2), and accepting Sodom's king's goods would compromise that testimony. The covenant-identity (YHWH as patron/benefactor) must not be obscured by an alternative patronage narrative (king of Sodom as Abram's benefactor).</p>""",
    "24": """<p>"I will accept nothing but what my men have eaten and the share that belongs to the men who went with me" — the exception for Aner, Eshkol, and Mamre (Abram's Amorite allies who fought with him) is a covenant-justice provision: they took the risk, they deserve the reward. Abram's personal covenant-commitment (no goods from Sodom) does not extend to his allies who have no such covenant obligation. The careful distinction between his personal oath-commitment and the legitimate claims of his coalition partners demonstrates the ANE principle that binding oaths create obligations only for the oath-taker, not for non-parties.</p>"""
  },
  "15": {
    "1": """<p>"The word of the LORD came to Abram in a vision (<em>bammaḥăzeh</em>)" — the first use of the prophetic vision-formula in the Bible. The formula "the word of the LORD came to" (<em>wayĕhî dĕḇar-YHWH ʾel</em>) is the standard opening of prophetic oracles throughout the OT (Jer 1:2; Ezek 1:3; Hos 1:1; Joel 1:1; Zeph 1:1; Hag 1:1). Its use here establishes Abram as a prophet-figure receiving prophetic revelation. "Do not be afraid, Abram" (<em>ʾal-tîrāʾ</em>) — the divine reassurance formula used in covenant-initiation moments throughout the OT (26:24 to Isaac; 46:3 to Jacob; Isa 41:10; Dan 10:12). The timing ("after this") connects to the Melchizedek encounter and the king of Sodom's offer: YHWH reassures Abram that refusing Sodom's wealth was right — YHWH himself is Abram's shield and reward.</p>""",
    "2": """<p>Abram's heir-crisis — "the one who will inherit my estate is Eliezer of Damascus" — reflects a specific ANE legal practice documented in the Nuzi tablets (Hurrian law documents from ca. 1500 BCE). A childless man could adopt a household slave or a free person as heir; the adopted heir served his adoptive parent and received the inheritance at death. If a natural son was subsequently born, the adopted heir was displaced in favor of the natural son. Eliezer's status as Abram's "heir-apparent" under this custom explains the crisis: the covenant-promise of offspring (12:2; 13:16) has not been fulfilled, and by ANE legal default, the estate will pass to a non-biological heir. The covenant appears to be failing.</p>""",
    "3": """<p>"You have given me no children; so a servant in my household will be my heir" — the repetition of the complaint (v2 and v3) intensifies Abram's anguish. The double statement — first naming Eliezer specifically (v2), then restating the general principle (v3) — mirrors the ANE practice of emphasizing important claims through repetition. The lament is addressed to YHWH as an accusation: "you have given me no children" (<em>lōʾ nātattāh lî zāraʿ</em>) — the absence of offspring is YHWH's doing, not merely biological accident. Abram holds YHWH responsible for the fulfillment of a promise that YHWH made.</p>""",
    "4": """<p>"This man will not be your heir, but a son who is your own flesh and blood (<em>ʾăšer yēṣēʾ mimméʿêkā</em>)" — literally "who will come out from your bowels/body." The anatomical specificity ("from your own body") rules out the adoption solution and insists on biological descent. YHWH's answer directly addresses the Nuzi-law custom: the covenant-heir will not be the legally adopted Eliezer but a naturally born son of Abram's own body. The covenant cannot be legally circumvented by ANE adoption customs — the promise requires biological fulfillment, which points forward to the miraculous birth of Isaac through the post-menopausal Sarah (ch21).</p>""",
    "5": """<p>"Look up at the sky and count the stars — if indeed you can count them. So shall your offspring be" — the night-sky star count was a recognized ANE image for uncountable multitude (Deut 1:10; 10:22; 28:62). YHWH takes Abram outside (<em>wayyôṣēʾ ʾōtô haḥûṣāh</em>) for the visual object lesson — the theophany is not merely verbal but sensory. Ancient star-counts in Mesopotamian astronomy numbered approximately 1000-1500 visible stars (the Mul.Apin astronomical text from ca. 1000 BCE). The promise's scale — exceeding the countable — confronts Abram's present reality (zero children, 85 years old) with the divine commitment to future uncountability.</p>""",
    "6": """<p>"Abram believed (<em>heʾĕmîn</em>) the LORD, and he credited (<em>wayyaḥšĕḇehā</em>) it to him as righteousness (<em>ṣĕdāqāh</em>)" — the verse's vocabulary is commercially precise. <em>Heʾĕmîn</em> (Hiphil of <em>ʾāman</em>) means to treat as firm/reliable — Abram leaned his weight on YHWH's word-promise as if it were solid ground. <em>Ḥāšaḇ</em> (to reckon/account/credit) is an accounting term — the same verb used for reckoning financial transactions in commercial contexts (Lev 25:27,50-52). YHWH entered Abram's trust-response in the ledger as a <em>ṣĕdāqāh</em> (righteous-standing) credit. The faith was real before the law existed — this verse is the foundation of Paul's argument in Rom 4:3 and Gal 3:6 that justification by faith (not law-keeping) was always YHWH's covenant pattern.</p>""",
    "7": """<p>"I am the LORD, who brought you out of Ur of the Chaldeans" — the covenant self-introduction formula with the redemption-history grounding. The parallel with the Sinai formula (Exod 20:2: "I am the LORD your God, who brought you out of Egypt") is deliberate: YHWH defines himself by redemptive action. Abram's Ur is to him what Egypt is to Israel — the place of origin from which YHWH redeemed. The covenant God is always the God-who-acts: his identity is inseparable from his covenantal history with his people. "To give you this land to take possession of it" restates the land promise of 12:7; 13:15 — the repeated land-promise reinforces the covenant's land-dimension as inseparable from the offspring-dimension.</p>""",
    "8": """<p>"How can I know (<em>bammāh ʾēḏaʿ</em>) that I will gain possession of it?" — Abram's request for a sign is not faithless skepticism (he has just been credited with righteousness for believing) but a covenant-confirmation request. In ANE treaty-making, covenant ratification required a formal ceremony to make the commitment legally binding. Abram is asking for the covenant-ceremony that will give him legal assurance, not expressing doubt about YHWH's character. The distinction matters for the narrative: the same Abram who "believed the LORD" (v6) also asks for covenant confirmation (v8) — these are not contradictory but sequential stages of covenant establishment.</p>""",
    "9": """<p>The covenant-ceremony animals — "a heifer (<em>ʿeglāh</em>), a goat (<em>ʿez</em>) and a ram (<em>ʾayil</em>), each three years old, along with a dove (<em>tōr</em>) and a young pigeon (<em>gôzāl yônāh</em>)" — are mature, fully developed animals, the best specimens for covenant-ceremony. The combination of large animals (heifer, goat, ram) and birds (dove, pigeon) anticipates the later Levitical sacrificial categories — both large animals and birds are used in the Levitical system (Lev 1:2-17). The three-year-old specification for the larger animals (fully mature but not yet aged) appears to be the standard for formal covenant-ceremonies, though this is the only Genesis instance.</p>""",
    "10": """<p>The cutting of the animals "in two" (<em>wayyibaṭṭēr ʾōtām bātāwek</em>) and arrangement of the halves "opposite each other" is the technical description of the <em>bĕrît bên habbĕtārîm</em> (covenant between the pieces) ceremony. Jeremiah 34:18-19 explicitly preserves the same covenant-cutting ritual with its legal interpretation: those who walk between the divided animals commit themselves to the same fate as the animals if they break the covenant. The birds are not divided — possibly because they are too small, or because ancient convention distinguished between avian and mammalian animals in covenant ceremonies. Abram's arrangement of the pieces "opposite each other" (<em>ʾîš-bitrô liqraʾt rēʿēhû</em>) creates the corridor through which the covenant-parties will walk.</p>""",
    "11": """<p>"Birds of prey (<em>ʿayiṭ</em>) came down on the carcasses, but Abram drove them away" — the birds of prey represent a ritual threat to the covenant ceremony's integrity. Abram's vigil over the carcasses (driving away the predators) is his active participation in the covenant-making even as the passive party who will sleep through the divine action (v12). The birds of prey as symbols of disruption and threat are later identified in prophetic imagery with foreign nations threatening Israel (Jer 12:9: "Has my inheritance become to me like a speckled bird of prey?" — where the surrounding birds of prey are enemy nations attacking Israel).</p>""",
    "12": """<p>"As the sun was setting, Abram fell into a deep sleep (<em>tardemāh</em>)" — the same word used for Adam's deep sleep in Gen 2:21, during which God formed Eve. The deep sleep is a theophanic trance state — the human party rendered passive so that YHWH can act alone in the covenant ceremony. The darkness that came over Abram is characterized as "thick and dreadful" (<em>ʾêmāh ḥăšēḵāh gĕḏōlāh</em>, a horror of great darkness) — the overwhelming divine darkness associated with theophanic encounter and covenant-judgment (cf. the thick darkness of Sinai, Exod 20:21; Deut 4:11; the darkness over Egypt, Exod 10:21-23). The terror prepares Abram for the revelation of his descendants' coming suffering.</p>""",
    "13": """<p>"Know for certain (<em>yādōaʿ tēḏaʿ</em>, the double-verb intensifier for absolute certainty) that for four hundred years your descendants will be strangers (<em>gēr</em>) in a country not their own and... enslaved (<em>waʿăḇādûm</em>) and mistreated (<em>wĕʿinnû</em>)." The 400-year prediction spans the Egyptian sojourn — from Jacob's descent (46:6) to the Exodus. The word <em>gēr</em> (stranger/resident alien) describes the status of having no land-rights in a foreign country — the covenant-people who have been promised land will spend 400 years landless and powerless. The word <em>ʿinnû</em> (mistreated/afflicted) uses the same root as Hagar's oppression (16:6) and Israel's Egyptian oppression (Exod 1:11-12). The covenant is fulfilled through suffering, not despite it.</p>""",
    "14": """<p>"But I will punish (<em>dān ʾānōkî</em>, literally 'I myself will judge') the nation they serve as slaves, and afterward they will come out with great possessions (<em>birkuš gādōl</em>)" — the Exodus and the plundering of Egypt are predicted. "Come out with great possessions" is fulfilled in Exod 12:35-36 (Israel departing Egypt with silver and gold). The verb <em>dān</em> (to judge/execute judgment) anticipates the ten plagues — YHWH's judicial action against Egypt for enslaving the covenant people. The sequence: suffering (v13) → divine judgment on the oppressor (v14) → departure with wealth (v14) → return to the land (v16) is the exact arc of the Exodus narrative, predicted 400 years before it occurs.</p>""",
    "15": """<p>"You, however, will go to your ancestors in peace and be buried at a good old age" — Abram is protected from the suffering his descendants will face. The phrase "go to your ancestors" (<em>tābôʾ ʾel-ʾăḇōtêkā bĕšālôm</em>) is the standard OT idiom for a peaceful death among one's people — in contrast to dying in war or exile. Abraham will die at 175 (25:7) and be "buried" by his sons Isaac and Ishmael at Machpelah (25:9) — fulfilling this promise. The covenant's promises extend beyond the covenant-initiator's death: what Abram was promised, his descendants will receive. This generational extension is characteristic of biblical covenant structure.</p>""",
    "16": """<p>"In the fourth generation your descendants will come back here, for the sin of the Amorites has not yet reached its full measure (<em>lōʾ-šālēm ʿăwôn hāʾĕmōrî</em>)" — a theologically remarkable statement about divine patience. The delay of the Israelite conquest is not due to Israel's unreadiness but to the Amorites' not-yet-full guilt. YHWH is patient with the Canaanites, granting them time before judgment falls. The same divine patience-with-the-wicked pattern appears in 2 Pet 3:9 ("the Lord is not slow in keeping his promise... he is patient, not wanting anyone to perish"). "Four generation" and "400 years" (v13) may count differently — a generation in ANE reckoning could be 100 years (cf. the 100-year generation implied in v13's arithmetic: 4 × 100 = 400).</p>""",
    "18": """<p>"On that day the LORD made a covenant (<em>kārat bĕrît</em>) with Abram" — the formal covenant-cutting language (<em>kārat</em>, to cut) derives from the animal-cutting ceremony just enacted. The land boundaries — "from the Wadi of Egypt (<em>naḥal miṣrayim</em>, the Wadi el-Arish in the Sinai) to the great river, the Euphrates" — define the maximally extended Abrahamic territory. This "greater Israel" boundary was partially realized under Solomon (1 Kgs 4:21; 2 Chr 9:26) and has never been fully occupied. The boundary formula appears as a goal in Deut 1:7; 11:24; Josh 1:4 — the outer limit of the conquest mandate. The covenant formally ratified in ch15 is the legal foundation for all subsequent Israelite land claims.</p>""",
    "19": """<p>The first five nations of the land grant — Kenites (<em>Qênî</em>, associated with the Midianite priest Jethro/Hobab, Num 10:29; and with the Amalekite region, 1 Sam 15:6), Kenizzites (<em>Qĕnizzî</em>, associated with Caleb's clan and Edomite territory, Num 32:12; Gen 36:11), Kadmonites (<em>Qaḏmōnî</em>, literally "eastern ones" — a generic term for eastern Arabian peoples) — represent peoples of the south and southeast of Canaan whose territories fall within the promised boundaries. The list of ten nations (vv19-21) is the most comprehensive enumeration of Canaan's pre-Israelite inhabitants in the OT, surpassing the standard "seven nations" formula of Deut 7:1.</p>""",
    "20": """<p>Hittites (<em>Ḥittî</em>, see 10:15 — the Canaanite Hittites of the patriarchal period distinct from the imperial Hittites of Anatolia), Perizzites (<em>Pĕrizzî</em>, "people of the open country," 13:7), Rephaites (<em>Rĕpāʾîm</em>, giant peoples associated with Bashan and Transjordan — 14:5; Deut 2:11,20; 3:11,13) — three groups whose territories span the hill country (Hittites, Perizzites) and the Transjordanian highlands (Rephaites). The Rephaites' inclusion is notable since their territory is east of the Jordan — confirming that the promised land boundaries of v18 (to the Euphrates) encompass Transjordanian territories that Israel will later control (Gilead, Bashan).</p>""",
    "21": """<p>Amorites (<em>ʾĕmōrî</em> — the comprehensive Syro-Canaanite people group; the sin of the Amorites was mentioned in v16), Canaanites (<em>Kĕnaʿănî</em>), Girgashites (<em>Girgāšî</em>, a Canaanite group mentioned in Josh 3:10; 24:11), Jebusites (<em>Yĕḇûsî</em> — the pre-Israelite inhabitants of Jerusalem whom David will later conquer, 2 Sam 5:6-8) — the final four nations. The Jebusite mention, with Jerusalem as their city, provides an implicit forward-reference to David's conquest of the Jebusite stronghold. The complete ten-nation list of vv19-21 frames the Abrahamic covenant's land promise as comprehensive: the entire region from the Wadi of Egypt to the Euphrates, occupied by these ten peoples, is promised to Abraham's descendants.</p>"""
  },
  "16": {
    "1": """<p>"Sarai, Abram's wife, had borne him no children. But she had an Egyptian slave (<em>šipḥāh miṣrît</em>) named Hagar" — the three-part statement (barren wife / but / Egyptian slave) sets up the narrative's tension economically. The word <em>šipḥāh</em> (female slave, belonging to the household) identifies Hagar's legal status: she is Sarai's property, not a free person. Her Egyptian nationality connects her to the Egypt episode of ch12 — she may be among the servants acquired from Pharaoh's household (12:16). The barrenness of the covenant-mother (noted also for Rebekah, 25:21, and Rachel, 29:31) is the recurring crisis through which YHWH demonstrates covenant power operating against biological impossibility.</p>""",
    "2": """<p>Sarai's proposal — "perhaps I can build a family (<em>ʾibbāneh</em>) through her" — embeds a Hebrew wordplay: the verb <em>bānāh</em> (to build) produces <em>ʾibbāneh</em> (I can be built/get a son), exploiting the phonetic connection between <em>bānāh</em> (build) and <em>bēn</em> (son). The legal background for the proposal is well attested: the Code of Hammurabi (Laws 144-146) and Nuzi adoption tablets (ca. 1500 BCE) describe the practice of a barren wife providing her husband with a slave as surrogate mother, with the resulting child legally recognized as the wife's offspring. Sarai's proposal is not immoral by the standards of her cultural-legal context — it is the recognized ANE legal remedy for barrenness. The moral complexity lies in the conflict between this culturally legitimate solution and the covenant's supernatural fulfillment trajectory.</p>""",
    "3": """<p>"After Abram had been living in Canaan ten years" — ten years of waiting in the covenant land with no heir despite the repeated promise. The time marker intensifies the crisis: the covenant-promise of 12:2 has been reiterated (13:16; 15:5) but not fulfilled. Sarai "gave" (<em>wattitten</em>) Hagar "to her husband Abram to be his wife (<em>lô lĕʾišāh</em>)" — the formal giving confers on Hagar the legal status of a secondary wife, not merely a surrogate slave. This status elevation will contribute to the social tension of v4: Hagar now has a wife's claims, not merely a slave's subordination. The formal marriage arrangement is the culturally expected legal mechanism, but it creates the social problem the narrative will address.</p>""",
    "4": """<p>"When she knew she was pregnant, she began to despise (<em>watteqal</em>) her mistress" — the elevation of a slave through pregnancy created well-documented social tensions in the ANE. The Code of Hammurabi (Law 146) addresses this exact situation: a slave given as surrogate who "claims equality with her mistress because she has borne children" may be reduced back to slave status but may not be sold. The verb <em>qālal</em> (to be light/of little weight/of little account) is the opposite of <em>kāḇaḏ</em> (to be heavy, honored) — Hagar is treating Sarai as of little social weight, reversing the honor-hierarchy of mistress and slave. The pregnancy has shifted Hagar's self-perception of her standing in the household.</p>""",
    "5": """<p>Sarai's complaint — "May the LORD judge (<em>yišpôṭ YHWH</em>) between you and me" — invokes divine arbitration. The formula "may the LORD judge between us" (<em>yišpôṭ YHWH bênî ûḇênekā</em>) is a standard appeal to divine jurisprudence when human resolution is inadequate or unavailable (cf. 1 Sam 24:12,15: David appeals to YHWH as judge against Saul). Sarai's accusation ("you are responsible for the wrong I am suffering") holds Abram accountable as household head for failing to maintain the social order he was legally responsible to preserve. The Hammurabi Code (Law 146) places the resolution of such conflicts with the husband — Sarai is correct that Abram's passivity is part of the problem.</p>""",
    "6": """<p>"Your slave is in your hands (<em>yādēk</em>)" — Abram returns Hagar to Sarai's authority. The Hebrew idiom "in your hands" denotes legal jurisdiction and power-over. Abram's abdication of his role as mediator-adjudicator leaves the conflict unresolved and Hagar without protection. "Sarai mistreated (<em>wattĕʿannehā</em>) Hagar" — the Piel of <em>ʿānāh</em> (to oppress/afflict/humble) is the same verb used for Israel's oppression in Egypt (Exod 1:11,12; Deut 26:6,7) and for Hagar's own affliction that YHWH "heard" (v11). The narrative echo is pointed: Sarai's treatment of Hagar parallels Egypt's treatment of Israel — the oppressed covenant-household member will become the oppressing household against the household's vulnerable dependent.</p>""",
    "7": """<p>"The angel of the LORD (<em>malʾak YHWH</em>) found Hagar near a spring in the desert; it was the spring that is beside the road to Shur" — the <em>malʾak YHWH</em> (messenger/angel of YHWH) makes his first appearance in the Bible in this encounter with Hagar. That the first angelic appearance in Scripture is to a runaway Egyptian slave woman — not to a patriarch, a priest, or a warrior — is theologically significant: the divine attention reaches the most marginal figure in the narrative. The road to Shur runs from Canaan through the Sinai toward Egypt — Hagar is heading home. The spring (<em>ʿēn</em>, a perennial spring) in the desert is a life-giving location, marking divine provision in the barren wilderness before any words are spoken.</p>""",
    "8": """<p>"Hagar, slave of Sarai, where have you come from, and where are you going?" — the angel's double question echoes the pattern of divine interrogation in Genesis: "Where are you?" (3:9 to Adam), "Where is your brother Abel?" (4:9 to Cain). The questions are not requests for information but invitations to honest self-examination and acknowledgment of one's situation. The angel's identification of Hagar by her status ("slave of Sarai") does not diminish her — it acknowledges her real social location. Hagar's transparent answer ("I'm running away from my mistress Sarai") is the honesty that the divine interrogation elicits. She names the reality without evasion.</p>""",
    "9": """<p>"Go back to your mistress and submit (<em>ʿinnî</em>) to her" — the return command uses the same verb (<em>ʿānāh</em>) that described Sarai's mistreatment of Hagar in v6. YHWH is telling Hagar to return to the source of her oppression and to humble herself before it. The instruction is difficult; its rationale is not given here but becomes clear from the promise that follows (vv10-12): Ishmael's birth and future must occur within the covenant-household structure that Abram and Sarai represent. The return is not an endorsement of Sarai's mistreatment but a providential direction for Hagar's protection and Ishmael's birth in safe conditions.</p>""",
    "10": """<p>"I will increase (<em>harbāh ʾarbbeh</em>, the double-verb intensifier) your descendants so much that they will be too numerous to count" — the promise to Hagar uses the same uncountable-offspring formula given to Abram (13:16; 15:5). Hagar receives the offspring-promise directly, in the same language as the patriarch — she is not a peripheral figure receiving lesser blessings but a recipient of genuine divine covenant-promise. This is the only instance in Genesis where a woman receives the promise of innumerable descendants directly without male mediation. The Ishmael promise establishes that the Abrahamic covenant's overflow reaches even the excluded-but-related line.</p>""",
    "11": """<p>"You shall name him Ishmael (<em>Yišmāʿēl</em>), for the LORD has heard (<em>šāmaʿ</em>) your misery (<em>ʿŏnyyēk</em>)" — the name Ishmael = "God hears" (<em>šāmaʿ</em> + <em>ʾēl</em>). The root <em>ʿŏnî</em> (misery/affliction) in the reason-clause uses the same root as Sarai's <em>ʿinnû</em> (mistreated, v6) and Israel's Egyptian <em>ʿānāh</em> (oppression, Exod 1:11). YHWH heard the cry of the afflicted slave woman and named her son after the divine hearing. The name embeds the memory of divine attention into the child's identity: every time Ishmael's name is spoken, it recalls the moment YHWH heard a marginalized woman's suffering. In this, Ishmael's name-narrative mirrors Israel's — a people defined by the God who heard their cry (Exod 2:24: "God heard their groaning").</p>""",
    "12": """<p>"He will be a wild donkey (<em>pere</em>) of a man; his hand will be against everyone and everyone's hand against him, and he will live in hostility toward all his brothers" — the wild donkey (<em>pere</em>) is the biblical symbol for the free, untamable desert nomad (Job 39:5-8: "Who let the wild donkey go free? Who untied its ropes? I gave it the wasteland as its home, the salt flats as its habitat. It laughs at the commotion in the town... It ranges the hills for its pasture"). This is not a curse but a characterization of the Arabian nomadic peoples descended from Ishmael — independent, strong, living by their own terms in the open desert. The phrase "live in hostility toward all his brothers" (<em>ʿal-pĕnê kol-ʾeḥāyw yiškon</em>) can also be translated "he will live in the presence of / alongside all his brothers" — a geographical description of the Arabian peoples dwelling adjacent to but distinct from their settled Semitic neighbors.</p>""",
    "13": """<p>"You are the God who sees me (<em>ʾAttāh ʾEl rōʾî</em>)" — Hagar's naming of God is unique: she is the only person in the entire OT to give God a name. The theophanic encounter is mutual — YHWH saw Hagar (v13a) and Hagar saw YHWH (v13b: "I have now seen the One who sees me"). The mutual seeing (<em>rāʾāh</em>) is the passage's central theological image: the God of Israel is not only the God of patriarchs but the God who sees every person, even the Egyptian slave woman fleeing through the desert. The name <em>ʾEl Roʾî</em> (the God who sees) will be associated with the well Beer Lahai Roi and later with Isaac's residence (24:62; 25:11) — the covenant patriarch inherits the location where the excluded found divine attention.</p>""",
    "14": """<p>"That is why the well was called Beer Lahai Roi (<em>bĕʾēr laḥay rōʾî</em>)" — "well of the Living One who sees me." The place-name etymology preserves the double divine attribute: YHWH is the Living One (<em>laḥay</em>, a theophanic divine title — cf. ʾĒl Ḥay, the Living God, Hos 1:10; Ps 42:2) and the God who sees (<em>rōʾî</em>). The geographic precision — "between Kadesh and Bered" — locates the well in the northern Negev/Sinai boundary region, the same area where Israel will later camp during the wilderness wandering (Kadesh, Num 13:26; 20:1). The well becomes a permanent geographic memorial to the divine-seeing encounter, associated in the text with Isaac's later residence, connecting the covenant-line patriarch to the site of grace given to the excluded.</p>""",
    "15": """<p>The brief birth narrative — "Hagar bore Abram a son, and Abram gave the name Ishmael to the son she had borne" — is notably compact compared to the extended attention given to the theophany in vv7-14. The naming is Abram's: by giving the angel-designated name to the child, Abram acknowledges both the divine revelation to Hagar and his paternity of Ishmael. The formal naming by the father is the ANE act of legal recognition — Abram publicly claims Ishmael as his son, consistent with the secondary-wife legal arrangement of v3. Ishmael's legal status as Abram's heir (under the slave-adoption custom) remains in effect until Isaac's birth (ch21).</p>""",
    "16": """<p>"Abram was eighty-six years old when Hagar bore him Ishmael" — the age notation maintains the Genesis genealogy's chronological tracking. Abram was 75 at the call (12:4), has been in Canaan ten years (16:3), and is now 86. The 13 years between Ishmael's birth (86) and the covenant renewal of ch17 (when Abram is 99 and Ishmael is 13) mark a period of silence — the narrative skips from Ishmael's birth directly to the covenant-renewal, suggesting a long waiting period during which Abram presumably regarded Ishmael as the covenant-heir. The 13-year gap before Isaac's promise (17:1) is the final extension of the covenant-patience: YHWH will wait 13 more years before revealing that Ishmael is not the covenant-heir.</p>"""
  }
}

def main():
    existing = load_comm('mkt-context', 'genesis')
    before_count = sum(len(v) for v in existing.values())
    merge_comm(existing, GENESIS_CONTEXT)
    save_comm('mkt-context', 'genesis', existing)

    result = load_comm('mkt-context', 'genesis')
    after_count = sum(len(v) for v in result.values())
    print(f'  Verses added: {after_count - before_count}')
    for ch in [13, 14, 15, 16]:
        ck = str(ch)
        n = len(result.get(ck, {}))
        print(f'  Ch {ch}: {n} verses present')
    total_chs = len(result)
    total_vv = sum(len(v) for v in result.values())
    print(f'  Genesis context total: {total_chs} chapters, {total_vv} verses')
    print('Genesis 13–16 mkt-context written.')

if __name__ == '__main__':
    main()
